function Counter() {
  const [state, dispatch] = useReducer(
    (state, action) => {
      switch (action.type) {
        case 'increment': return { count: state.count + action.step };
        default: return state;
      }
    },
    { count: 0 }
  );

  return (
    <div>
      <span>{state.count}</span>
      <button onClick={() => dispatch({ type: 'increment', step: 3 })}>+</button>
    </div>
  );
}

